import{_ as a,o,c as t,a0 as r}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"🌐 NEXUS CORE WIKI v4.0","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/wiki/NEXUS_CORE_WIKI.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/wiki/NEXUS_CORE_WIKI.md","lastUpdated":1782593311000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/wiki/NEXUS_CORE_WIKI.md"};function n(s,e,d,c,l,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="🌐-nexus-core-wiki-v4-0" tabindex="-1">🌐 NEXUS CORE WIKI v4.0 <a class="header-anchor" href="#🌐-nexus-core-wiki-v4-0" aria-label="Permalink to &quot;🌐 NEXUS CORE WIKI v4.0&quot;">​</a></h1><p>&gt; <strong>Status:</strong> Canônico | <strong>Versão:</strong> 4.0 | <strong>Codinome:</strong> Legacy of Sovereignty</p><p>A Wiki Canônica do NEXUS serve como a autoridade definitiva sobre a arquitetura e operação do sistema. O NEXUS não é apenas uma ferramenta de busca; é uma infraestrutura de memória externa projetada para sustentar a continuidade cognitiva de agentes de IA em bases de código complexas.</p><hr><h2 id="_1-o-que-o-nexus-e-o-sistema-bipartido" tabindex="-1">1. O Que o NEXUS é (O Sistema Bipartido) <a class="header-anchor" href="#_1-o-que-o-nexus-e-o-sistema-bipartido" aria-label="Permalink to &quot;1. O Que o NEXUS é (O Sistema Bipartido)&quot;">​</a></h2><p>O NEXUS opera como um <strong>Sistema de Referencial Cruzado Bipartido</strong>. Ele resolve o paradoxo da janela de contexto limitada das LLMs através de uma separação clara entre intenção semântica e realidade material.</p><ul><li><strong>O Espaço Vetorial (Qdrant / T3) — O GPS:</strong> Atua como a bússola do sistema. Ele mapeia &quot;intenção&quot; e &quot;proximidade semântica&quot;. É fluido, intuitivo e opera em Nível 1 (Abstrações L1). Localiza o &quot;bairro&quot; onde a informação reside.</li><li><strong>O Espaço Relacional (PostgreSQL / T2-T4) — O Mapa da Prefeitura:</strong> Contém o &quot;CEP&quot; exato e os &quot;tijolos&quot; (L0 - código bruto). É rígido, determinístico e mapeia dependências através de grafos e links (<code>hilbert_bridge</code>).</li></ul><p><strong>A Promessa:</strong> O sistema localiza a intenção no T3 e reidrata a IA com o código exato do T2, eliminando a necessidade de ler o repositório inteiro e prevenindo a deriva semântica.</p><hr><h2 id="_2-arquitetura-em-camadas-t2-gt-t4" tabindex="-1">2. Arquitetura em Camadas (T2 -&gt; T4) <a class="header-anchor" href="#_2-arquitetura-em-camadas-t2-gt-t4" aria-label="Permalink to &quot;2. Arquitetura em Camadas (T2 -&amp;gt; T4)&quot;">​</a></h2><p>O NEXUS organiza o conhecimento em níveis de processamento (Tiers) para garantir uma <strong>compressão semântica de 17.6x</strong>.</p><h3 id="t2-postgresql-a-ancora-canonica" tabindex="-1">T2: PostgreSQL (A Âncora Canônica) <a class="header-anchor" href="#t2-postgresql-a-ancora-canonica" aria-label="Permalink to &quot;T2: PostgreSQL (A Âncora Canônica)&quot;">​</a></h3><p>O T2 armazena a verdade material do sistema.</p><ul><li><strong>Blobs:</strong> Binários e arquivos originais com hashes de integridade.</li><li><strong>Abstractions (L1):</strong> Resumos semânticos gerados por LLMs a partir de janelas deslizantes (Sliding Window) de código bruto (L0).</li><li><strong>Relational Graph:</strong> Tabelas que mapeiam a identidade e versão de cada componente.</li></ul><h3 id="t3-qdrant-a-porta-de-entrada" tabindex="-1">T3: Qdrant (A Porta de Entrada) <a class="header-anchor" href="#t3-qdrant-a-porta-de-entrada" aria-label="Permalink to &quot;T3: Qdrant (A Porta de Entrada)&quot;">​</a></h3><p>Responsável pela busca por proximidade vetorial.</p><ul><li>Indexa as <strong>Abstrações L1</strong> geradas no T2.</li><li>Permite consultas em linguagem natural que são traduzidas para vetores densos.</li><li>Funciona como o indexador de &quot;sementes&quot; para a expansão subsequente.</li></ul><h3 id="t4-navegacao-topologica-o-motor-de-contexto" tabindex="-1">T4: Navegação Topológica (O Motor de Contexto) <a class="header-anchor" href="#t4-navegacao-topologica-o-motor-de-contexto" aria-label="Permalink to &quot;T4: Navegação Topológica (O Motor de Contexto)&quot;">​</a></h3><p>Diferente de um RAG comum que usa apenas <code>top_k</code>, o T4 navega pelas relações.</p><ul><li><strong>PPR (Personalized PageRank):</strong> Difusão de relevância a partir das sementes do T3.</li><li><strong>Hilbert Bridge:</strong> Conexões topológicas que unem abstrações relacionadas, permitindo saltos entre arquivos dependentes.</li><li><strong>Causalidade:</strong> Navega por relações de &quot;quem chama quem&quot; para montar um pacote de contexto coerente.</li></ul><hr><h2 id="_3-motor-de-busca-nexus-context-py" tabindex="-1">3. Motor de Busca: <code>nexus_context.py</code> <a class="header-anchor" href="#_3-motor-de-busca-nexus-context-py" aria-label="Permalink to &quot;3. Motor de Busca: `nexus_context.py`&quot;">​</a></h2><p>O <code>nexus_context.py</code> é a interface única de execução do motor NEXUS. Ele unifica a busca vetorial com a expansão topológica.</p><h3 id="recursos-principais" tabindex="-1">Recursos Principais: <a class="header-anchor" href="#recursos-principais" aria-label="Permalink to &quot;Recursos Principais:&quot;">​</a></h3><ul><li><strong>HyDE (Hypothetical Document Embeddings):</strong> Traduz perguntas coloquiais em hipóteses técnicas sintéticas, aumentando drasticamente a precisão da busca em código.</li><li><strong>PPR Diffusion:</strong> Expande as sementes iniciais para encontrar &quot;vizinhos&quot; relevantes no grafo.</li><li><strong>Context Packing:</strong> Formata o resultado em <strong>Context Packs</strong> (Packs de Contexto), que incluem tanto a visão geral (L1) quanto o código bruto (L0), prontos para consumo imediato por uma LLM.</li><li><strong>Zoom-In:</strong> Permite buscar os chunks L0 específicos ao redor de uma âncora L1.</li></ul><hr><h2 id="_4-versionamento-kanban-git-as-state-engine" tabindex="-1">4. Versionamento Kanban (Git as State Engine) <a class="header-anchor" href="#_4-versionamento-kanban-git-as-state-engine" aria-label="Permalink to &quot;4. Versionamento Kanban (Git as State Engine)&quot;">​</a></h2><p>O NEXUS trata o Git como um motor de snapshot de estado, não apenas para controle de versão social.</p><ul><li><strong>main (Canon):</strong> A fonte da verdade imutável. Contém apenas estados estáveis e verificados.</li><li><strong>draft (The Mill):</strong> Ramo de integração ativa. Onde múltiplos agentes fundem seus checkpoints.</li><li><strong>checkpoint (Safety Net):</strong> Ramos individuais por tarefa (ex: <code>checkpoint/task-123</code>). Commits representam checkpoints lógicos de estado, permitindo reversão granular.</li></ul><hr><h2 id="_5-survival-protocol-operacao-e-skills" tabindex="-1">5. Survival Protocol (Operação e Skills) <a class="header-anchor" href="#_5-survival-protocol-operacao-e-skills" aria-label="Permalink to &quot;5. Survival Protocol (Operação e Skills)&quot;">​</a></h2><p>Para operar o NEXUS com eficiência, utilize os recursos de &quot;Boot&quot; e as ferramentas locais.</p><h3 id="comandos-essenciais" tabindex="-1">Comandos Essenciais: <a class="header-anchor" href="#comandos-essenciais" aria-label="Permalink to &quot;Comandos Essenciais:&quot;">​</a></h3><ul><li><strong>Consultar o Córtex:</strong> <code>python3 scripts/nexus_context.py &quot;pergunta&quot; --ext .rs --hyde --pack</code></li><li><strong>Refinaria T2:</strong> <code>python3 scripts/t2_worker.py</code> (Processa chunks L0 para gerar L1).</li><li><strong>Ponte T3:</strong> <code>python3 scripts/t2_bridge.py</code> (Sincroniza T2 com Qdrant).</li></ul><h3 id="invariantes-de-sobrevivencia" tabindex="-1">Invariantes de Sobrevivência: <a class="header-anchor" href="#invariantes-de-sobrevivencia" aria-label="Permalink to &quot;Invariantes de Sobrevivência:&quot;">​</a></h3><ol><li><strong>T1 é Soberano:</strong> Em caso de divergência entre o banco de dados e o Filesystem, o Filesystem (T1) sempre vence.</li><li><strong>Zero Alucinação:</strong> Nunca deixe a LLM inventar código. Sempre forneça o contexto via <code>nexus_context.py</code>.</li><li><strong>Higiene de Ingestão:</strong> Arquivos de documentação em <code>docs/</code> devem possuir <code>nexus: ingestible: false</code> no frontmatter para evitar loops semânticos infinitos.</li></ol><hr><p><em>Documento gerado pelo protocolo Sisyphus para a v4.0 do NEXUS.</em></p>',38)])])}const g=a(i,[["render",n]]);export{m as __pageData,g as default};
